INSERT INTO reviews (client_id, artist_id, project_request_id, rating, body, created_at) VALUES ('4180ea8c-9e39-4c63-8387-ed1dd835b724', '186b842d-d05d-4689-84a0-27bf4d9cdc4e', NULL, '5', 'Mon deuxième tatouage avec Maya et toujours aussi impressionnée. Fine line parfaite, cicatrisation nickel.', '2026-06-23 10:57:01.507655+00');
INSERT INTO reviews (client_id, artist_id, project_request_id, rating, body, created_at) VALUES ('a3f4d29f-456c-487b-ba2a-fc791fd3cf2a', '186b842d-d05d-4689-84a0-27bf4d9cdc4e', NULL, '5', 'Accueil top, ambiance cool, résultat bluffant. Mon entourage me demande tous où j''ai fait ça !', '2026-06-23 10:57:01.507655+00');
INSERT INTO reviews (client_id, artist_id, project_request_id, rating, body, created_at) VALUES ('68949e3e-86f3-4a1f-8974-4b0d03ba3e5c', '186b842d-d05d-4689-84a0-27bf4d9cdc4e', NULL, '5', 'Elle a su retranscrire mon idée mieux que ce que j''avais imaginé. Un vrai talent.', '2026-06-23 10:57:01.507655+00');
INSERT INTO reviews (client_id, artist_id, project_request_id, rating, body, created_at) VALUES ('88df4f61-4710-42a0-a511-cf9bff2c0f97', '186b842d-d05d-4689-84a0-27bf4d9cdc4e', NULL, '4', 'Super pro, bonne communication avant le rdv. Le tatouage est magnifique, juste un peu long à caler les dates.', '2026-06-23 10:57:01.507655+00');
